INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (6979, 'Underpants-stealing gnomes, a talking Christmas poo, metrosexual Crab People…Every episode of this critically-acclaimed and award-winning show is packed with unforgettable adventures, cutting satire, and hilarious absurdity – from pissed off celebrities to talking towels to crime-fighting kids. So join Kyle, Stan, Kenny and Cartman for the all the dysfunction and all the excitement. For them, it''s just a part of growing up in South Park!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 3874, "Videos_Total": 4148, "Episode_Total": 268, "Feature_Films": 0, "Seasons_Total": 20}}', '{"Link_Desc": "For more on this show, visit the official <a href=\"http://www.southparkstudios.com/\" target=\"_blank\">South Park</a> site.", "KeyArt_URL": "https://ib3.hulu.com/show_key_art/6979?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/6979?size=476x268&region=US"}');
