INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (623750, 'Sabrina is a normal teenager, except for one thing -- she''s a witch! Guided by her aunts, who come from a long line of witches, and Salem, a mischievous warlock doing penance as a black cat, Sabrina continually struggles to harness her powers while wittingly wreaking havoc on friends and foes alike. While struggling through the growing pains associated with being a witch and getting into lots of harmless trouble along the way, Sabrina realizes that magic is not quite as easy as pointing your finger.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 163, "Episode_Total": 163, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/12844?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/12844?size=476x268&region=US"}');
