INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (10, 'Forensic anthropologist Dr. Temperance Brennan uses her uncanny ability to read clues left behind in bones to help FBI agent Seeley Booth solve murder cases. Based on the life of anthropologist and novelist Kathy Reichs.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 60, "Videos_Total": 306, "Episode_Total": 246, "Feature_Films": 0, "Seasons_Total": 12}}', '{"Link_Desc": "For insider news, photos, and more visit the official <a href=\"http://www.fox.com/bones/\" target=\"_blank\">Bones website</a>", "KeyArt_URL": "https://ib2.hulu.com/show_key_art/10?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/10?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (11226, 'A legendary queen of country music struggles to maintain her place in the spotlight while dealing with an ambitious rising pop-country vixen who wants to knock her off the throne. From executive producer Callie Khouri (writer of Thelma & Louise) comes this contemporary musical drama about love, power, money, family and music. ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 426, "Videos_Total": 533, "Episode_Total": 107, "Feature_Films": 0, "Seasons_Total": 5}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/11226?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/11226?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (22278, 'Mordecai – a sarcastic blue jay, and Rigby – a somewhat responsible raccoon, are best friends. They even work together at a park owned by Pops, a big lollipop-headed guy. Which seems normal enough. They’ve got a cranky gumball machine for a boss and they work alongside a Zen-like yeti named Skips. Yep. Everything is as regular as can be.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 220, "Videos_Total": 437, "Episode_Total": 217, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/22278?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/22278?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (22881, 'Rick and Morty is a show about a sociopathic scientist who drags his unintelligent grandson on insanely dangerous adventures across the universe. Created and executive produced by Dan Harmon (Community, Channel 101) and Justin Roiland (House of Cosbys).', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 21, "Videos_Total": 42, "Episode_Total": 21, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/22881?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/22881?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (6341, 'College is over but the party isn’t. Join three best buds as they share a job, a crash pad and a promise to never let work get in the way of a good time—on this raucously original series.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 69, "Videos_Total": 155, "Episode_Total": 86, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/6341?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
