INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (1861, 'Step through the stargate with SG-1, a team of soldiers and scientists, as they travel instantaneously to other planets to explore, forge alliances, defuse crises, establish trade, investigate ancient mysteries, and defend Earth from such hostile forces as the Goa''uld, the Replicators, and the Ori.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 214, "Episode_Total": 214, "Feature_Films": 0, "Seasons_Total": 10}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/1861?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/1861?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (29524, 'The Golden Girls is the story of four older women who share a house in Miami Beach, Florida. Bea Arthur plays Dorothy, a divorced school teacher, with a sardonic wit. Rue McClanahan plays Blanche, a man-hunting Southern Belle. Betty White plays Rose, a very sweet woman who is somewhat spacey. Rounding out the trio is Estelle Getty, playing Dorothy''s outspoken mother, Sophia. ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 181, "Episode_Total": 180, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/29524?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/29524?size=476x268&region=US"}');
