INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (21985, 'The year is 2020, and after a deadly virus has swept the planet, only one man is left on earth: Phil Miller (Will Forte). He used to be just an average guy who loved his family and hated his job. Now, in his RV, Phil searches the country for other survivors. He has traveled to every city, every town and every outpost in the United States, Mexico and Canada, and has found no one. As he returns to his hometown of Tucson, Phil comes to the painful realization that he is almost certainly the last living being on the face of the earth. All he wants is for someone – anyone – to find him in Tucson – preferably a woman.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 65, "Videos_Total": 113, "Episode_Total": 48, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/21985?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/21985?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (5638, 'Meet Yugi, an eager young freshman at Domino High School. Yugi and his best friends, Joey, Tristan, and Tea share a love of a cool new game that''s sweeping the nation...Duel Monsters! In this card-battling game, players pit different mystical creatures against one another in action-packed, high intensity duels.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 4, "Videos_Total": 240, "Episode_Total": 222, "Feature_Films": 0, "Seasons_Total": 5}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/5638?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/5638?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (23200, 'ELEMENTARY stars Jonny Lee Miller as detective Sherlock Holmes and Lucy Liu as Dr. Joan Watson in a modern-day drama about a crime-solving duo that cracks the NYPD’s most impossible cases.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 106, "Episode_Total": 106, "Feature_Films": 0, "Seasons_Total": 5}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/23200?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/23200?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (12844, 'Sabrina is a normal teenager, except for one thing -- she''s a witch! Guided by her aunts, who come from a long line of witches, and Salem, a mischievous warlock doing penance as a black cat, Sabrina continually struggles to harness her powers while wittingly wreaking havoc on friends and foes alike. While struggling through the growing pains associated with being a witch and getting into lots of harmless trouble along the way, Sabrina realizes that magic is not quite as easy as pointing your finger.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 163, "Episode_Total": 156, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/12844?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/12844?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (2458, 'From Executive Producer Mark Burnett comes an inventive new reality series you can sink your teeth into. Budding entrepreneurs with big ideas can still make their dreams come true and ABC is about to give them the chance to make it happen. Each week a group of self-made millionaires from all corners of the business world take their own hard earned money and offer everyday people their one true shot at making their dreams a reality. Some will sink, some will swim and some will be eaten alive.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 18, "Videos_Total": 23, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": "Get to know <a href=\"http://abc.go.com/primetime/sharktank/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">Shark Tank</a> on the official site!", "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2458?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2458?size=476x268&region=US"}');
