INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (6901, 'When four young wizards from the most destructive guild in Fiore team up to take jobs, they forge a bond more powerful than any magic and grow stronger with every mission. Whatever you do, don''t mess with these friends or you''ll get burned!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 336, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 8}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/6901?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/6901?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (177, 'Top Chef offers a fascinating window into the competitive, pressure-filled environment of world class cookery and the restaurant business at the highest level. The series features seventeen aspiring chefs who compete for their shot at culinary stardom and the chance to earn the prestigious title of "Top Chef."', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1510, "Videos_Total": 1713, "Episode_Total": 195, "Feature_Films": 0, "Seasons_Total": 13}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/177?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (9673, 'A former media relations consultant to the President, Olivia Pope (Kerry Washington) dedicates her life to protecting and defending the public images of our nation''s elite. After leaving the White House, the power consultant opened her own firm, hoping to start a new chapter -- both professionally and personally -- but she can''t seem to completely cut ties with her past. Slowly it becomes apparent that her staff, who specialize in fixing the lives of other people, can''t quite fix the ones closest at hand -- their own.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 167, "Videos_Total": 167, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": null}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (11217, 'After a meteor shower bursts from the heavens, raining destruction on the unsuspecting citizens of Smallville, years pass, and the healing process leaves the town''s inhabitants with scars and secrets. From the ashes of tragedy, a popular yet awkward teen attempts to decipher the meaning of his life and his clouded past.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 218, "Episode_Total": 218, "Feature_Films": 0, "Seasons_Total": 10}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/11217?size=476x268&region=US"}');
