INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (13482, 'The name Viking is synonymous with extreme violence and terror. But few people know what it was really like to live in the world of the Viking.  This scripted drama will use real characters from history to humanize the Viking and authentically re-create the Viking Age.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 49, "Episode_Total": 49, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/13482?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/13482?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (4483, 'Four estranged best friends are reunited one year after the queen bee of the group, Alison, goes missing. When they begin to receive disturbing messages from someone named “A”, how far will they go to bury their secrets?', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 7, "Videos_Total": 12, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "For more Pretty Little Liars go to the <a href=\"http://abcfamily.go.com/abcfamily/path/section_Shows+Pretty-Little-Liars/page_Detail&CID=09_Hulu_ABCFamily\" target=\"_blank\">official site!</a>", "KeyArt_URL": "https://ib1.hulu.com/show_key_art/4483?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/4483?size=476x268&region=US"}');
