INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (183, 'Project Runway is a reality competition where fashion designers fight for their big break in the fashion industry.  Designers compete in weekly challenges, presenting their work on the runway.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 163, "Videos_Total": 239, "Episode_Total": 78, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/183?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/183?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (2440, 'Murder, mob wars, and mansions? It’s just all in a day’s work for the residents of Port Charles, New York. With such notable characters as Sonny Corinthos (Maurice Benard) and Jason Morgan (Billy Miller), there’s never a dull moment – especially when you add to the mix their long-time revolving love affairs with Carly (Laura Wright), Samantha (Kelly Monaco), Elizabeth (Rebecca Herbst), Olivia (Lisa LoCicero), and Claudia (Sarah Brown). Couples like Robin and Patrick (Kimberly McCullough and Jason Thompson) and Maxie and Spinelli (Kirsten Storms and Bradford Anderson), and families like the quarreling (but lovable) Quartermaines, even out this dysfunctional town.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1052, "Videos_Total": 1062, "Episode_Total": 10, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Get character 101s and more at the official <a href=\"http://abc.go.com/shows/general-hospital/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">General Hospital</a> site.", "KeyArt_URL": "https://ib2.hulu.com/show_key_art/2440?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/2440?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (24499, 'A vast international plot explodes when a beautiful Jane Doe is discovered naked in Times Square, completely covered in mysterious, intricate tattoos with no memory of who she is or how she got there. But there''s one tattoo that is impossible to miss: the name of FBI agent Kurt Weller, emblazoned across her back. "Jane," Agent Weller and the rest of the FBI quickly realize that each mark on her body is a crime to solve, leading them closer to the truth about her identity and the mysteries to be revealed. From Executive Producer Greg Berlanti ("The Mysteries of Laura," "The Flash," "Arrow").', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 49, "Videos_Total": 94, "Episode_Total": 45, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/24499?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/24499?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (6375, 'Forget who gets to keep the ring, when a couple splits, the real question is, who gets to keep the friends? In this modern comedy, a couple''s break up will complicate all of their friends'' lives and make everyone question their choices. When life throws you for a curve, hold on tight to the people you love.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 139, "Videos_Total": 196, "Episode_Total": 44, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/6375?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/6375?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (12666, 'Catfish:  The TV Show brings together couples who''ve interacted solely through LCD screens.  Over the course of months they''ve supposedly fallen in love -- but what will happen when they meet in real life for the first time?', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 78, "Videos_Total": 155, "Episode_Total": 77, "Feature_Films": 0, "Seasons_Total": 5}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/12666?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/12666?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (2526, 'ABC’s distinctive late-night talk show features a diverse lineup of guests, including celebrities, athletes, comedians, politicians and human interest subjects. Along with a light-hearted and recognizable cast of characters, a hip house band and comedy bits in host Jimmy Kimmel’s inimitable style, the show additionally offers one of the funniest, freshest monologues on television today, drawing from all forms of topical media.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1605, "Videos_Total": 1614, "Episode_Total": 16, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Music, photos, showcases, jokes and much more: It''s all on the official <a href=\"http://abc.go.com/latenight/jimmykimmel/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">JKL</a> site.", "KeyArt_URL": "https://ib2.hulu.com/show_key_art/2526?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/2526?size=476x268&region=US"}');
