INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (19145, 'Based on the best-selling crime novels, Angie Harmon and Sasha Alexander star as detective Jane Rizzoli and medical examiner Maura Isles. Opposites in many ways -- Rizzoli is brash and tomboyish; the methodical and impeccably dressed Isles is often icy -- together, they use their brilliant minds to bust Boston''s most notorious criminals.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 105, "Episode_Total": 93, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/19145?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/19145?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (7560, 'Tim Allen returns to ABC in this comedy from Jack Burditt (30 Rock). Men may have built civilizations, invented the locomotive and created ESPN, but they''re about to find out that it''s not a man''s world anymore. You can''t get manlier than Mike Baxter. He''s the marketing director for an iconic outdoor sporting goods store, he loves to have adventures while he''s traveling for work and, of course, he drives a pick-up truck. While Mike is king of the hill at work, he''s the odd man out in a home that is dominated by women -- namely his wife, Vanessa, and their three daughters, 22- year-old Kristin, 17-year-old Mandy and 14-year-old Eve.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 2, "Videos_Total": 24, "Episode_Total": 22, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "To discuss and learn more about the show, visit the <a href=\"http://beta.abc.go.com/shows/last-man-standing?cid=hulu_lms\" target=\"_blank\">official Last Man Standing site</a>", "KeyArt_URL": "https://ib.hulu.com/show_key_art/7560?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/7560?size=476x268&region=US"}');
