INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (15138, 'In this modern-day twist on Washington Irving''s classic, ICHABOD CRANE is resurrected and pulled two and a half centuries through time to find that the world is on the brink of destruction, forcing him to team up with a contemporary police officer to unravel a mystery that dates back to the founding fathers.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 48, "Videos_Total": 101, "Episode_Total": 62, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/15138?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/15138?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (11258, 'From renowned, Emmy Award-winning executive producer Dick Wolf ("Law & Order" brand) and creators Derek Haas and Michael Brandt, the writing team behind "3:10 to Yuma," comes the high-octane drama "Chicago Fire," -- an edge-of-your-seat view into the lives of everyday heroes committed to one of America’s noblest professions.  For the firefighters, rescue squad and paramedics of Chicago Firehouse 51, no occupation is more stressful or dangerous, yet so rewarding and exhilarating.  These courageous men and women are among the elite who forge headfirst into danger when everyone else is running the other way and whose actions make the difference between life and death.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 65, "Videos_Total": null, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/11258?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/11258?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (2313, 'The ''Grey''s Anatomy'' spin-off focuses on neonatal surgeon Addison Forbes Montgomery, who has left Seattle Grace and moved to L.A., where she practices at the upscale Oceanside Wellness Clinic with her divorced medical-school friends Naomi and Sam Bennett.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 246, "Videos_Total": 357, "Episode_Total": 104, "Feature_Films": 0, "Seasons_Total": 6}}', '{"Link_Desc": "Get music, photos, recaps and much more on the <a href=\"http://abc.go.com/primetime/privatepractice/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">official Private Practice site</a>", "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2313?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2313?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (11266, 'A provocative yet sophisticated drama about four women and their love lives, their sex lives, their secrets, their lies, and above all, their friendship. From ABC Studios, and based on the hit BBC series of the same name, this is Executive Produced by Bob Sertner ("Revenge," "No Ordinary Family"), KJ Steinberg ("Gilded Lilys," "Gossip Girl") and Rina Mimoun ("Privileged," "Gilmore Girls"). ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 53, "Episode_Total": 52, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/11266?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/11266?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (26058, 'The Devil has come to Los Angeles…Based upon the characters created by Neil Gaiman, Sam Kieth and Mike Dringenberg for DC Entertainment’s Vertigo imprint, LUCIFER is the story of the original fallen angel. Bored and unhappy as the Lord of Hell, LUCIFER MORNINGSTAR (Tom Ellis has abandoned his throne and retired to L.A., where he owns Lux, an upscale nightclub.  Charming, charismatic and devilishly handsome, Lucifer is enjoying his retirement, indulging in a few of his favorite things – wine, women and song – when a beautiful pop star is brutally murdered outside of Lux. For the first time in roughly 10 billion years, he feels something awaken deep within him as a result of this murder. Compassion? Sympathy? The very thought disturbs him – as well as his best friend and confidante, MAZIKEEN aka MAZE (Lesley-Ann Brandt), a fierce demon in the form of a beautiful young woman.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 33, "Videos_Total": 54, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/26058?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/26058?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (1201, 'In The O.C., the lives of a group of friends and families are forever changed when an outsider arrives to their affluent community of Newport Beach in Orange County, California. From Josh Schwartz, the executive producer of Gossip Girl and Chuck, the series became a pop-culture phenomenon with its mix of heart, humor, drama and romance.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 3, "Videos_Total": 95, "Episode_Total": 92, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/1201?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/1201?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (14027, 'Straight-talking comic girl-next-door Amy Schumer is exposing herself -- and her messy world of dating, drinking and public debacles -- when she steps out from behind the microphone for an all-new, genre-busting comedy series.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 79, "Videos_Total": 118, "Episode_Total": 39, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/14027?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/14027?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (12867, 'Comedy series set in Seattle, WA, which chronicles the lives of an eloquently pompous radio show host Dr. Frasier Crane (Kelsey Grammer), his brazen radio producer Roz (Peri Gilpin), his competitive, high-brow brother Niles (David Hyde Pierce), their crotchety father Martin (John Mahoney) and his quirky live-in nurse Daphne (Jane Leeves). ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 254, "Episode_Total": 264, "Feature_Films": 0, "Seasons_Total": 11}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/12867?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/12867?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (28109, 'Twin brother and sister Dipper and Mabel Pines are in for an unexpected adventure when they spend the summer with their great uncle in the mysterious town of Gravity Falls, Oregon. Upon their arrival, Dipper and Mabel''s huckster great uncle, also known as Grunkle Stan, enlists the siblings'' help in running The Mystery Shack, a fun tourist trap he owns that overcharges unsuspecting customers. Although Dipper and Mabel quickly discover The Mystery Shack itself is a hoax, they sense there is something strange about their new town and together they begin to unlock the secrets of Gravity Falls.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 41, "Episode_Total": 40, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/28109?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/28109?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (398857, 'Underpants-stealing gnomes, a talking Christmas poo, metrosexual Crab People…Every episode of this critically-acclaimed and award-winning show is packed with unforgettable adventures, cutting satire, and hilarious absurdity – from pissed off celebrities to talking towels to crime-fighting kids. So join Kyle, Stan, Kenny and Cartman for the all the dysfunction and all the excitement. For them, it''s just a part of growing up in South Park!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 3874, "Videos_Total": 4148, "Episode_Total": 274, "Feature_Films": 0, "Seasons_Total": 20}}', '{"Link_Desc": "For more on this show, visit the official <a href=\"http://www.southparkstudios.com/\" target=\"_blank\">South Park</a> site.", "KeyArt_URL": "https://ib3.hulu.com/show_key_art/6979?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/6979?size=476x268&region=US"}');
