INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (702728, 'The Village Hidden in the Leaves is home to the stealthiest ninja in the land.  But twelve years earlier, a fearsome Nine-tailed Fox terrorized the village before it was subdued and its spirit sealed within the body of a baby boy.  Now that boy, Naruto, has grown up to become a hyperactive ninja-in-training who''s more interested in pranks than schoolwork...but Naruto is determined to become the greatest ninja ever!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 16, "Videos_Total": 605, "Episode_Total": 597, "Feature_Films": 0, "Seasons_Total": 9}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/1603?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/1603?size=476x268&region=US"}');
