INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (815133, 'Today''s American families come in all shapes and sizes. The cookie cutter mold of man + wife + 2.5 kids is a thing of the past, as it becomes quickly apparent in the bird''s eye view of ABC''s half-hour comedy, which takes an honest and often hilarious look at the composition and complexity of modern family life.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 68, "Videos_Total": 90, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Cast bios, photos and chat: Interact on the official <a href=\"http://beta.abc.go.com/shows/modernfamily?CID=09_Hulu_ABC\" target=\"_blank\">Modern Family</a> website.", "KeyArt_URL": "https://ib2.hulu.com/show_key_art/2553?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (241113, 'Archer chronicles an international spy agency and the lives of its employees. Although their work of espionage, reconnaissance missions, wiretapping and undercover surveillance is daunting and dangerous, every covert operation and global crisis is actually just another excuse for the staff to undermine, sabotage and betray each other for personal gain. ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 14, "Videos_Total": 94, "Episode_Total": 85, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/3433?size=476x268&region=US"}');
