INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (733732, 'Rick and Morty is a show about a sociopathic scientist who drags his unintelligent grandson on insanely dangerous adventures across the universe. Created and executive produced by Dan Harmon (Community, Channel 101) and Justin Roiland (House of Cosbys).', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 21, "Videos_Total": 42, "Episode_Total": 21, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/22881?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/22881?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (243062, 'This long-running animated comedy focuses on the eponymous family in the town of Springfield in an unnamed U.S. state. The head of the Simpson family, Homer, is not a typical family man. A nuclear-plant employee, he does his best to lead his family but often finds that they are leading him. The family includes loving, blue-haired matriarch Marge, troublemaking son Bart, overachieving daughter Lisa and baby Maggie. Other Springfield residents include the family''s religious neighbor, Ned Flanders, family physician Dr. Hibbert, Moe the bartender and police chief Clancy Wiggum.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 405, "Videos_Total": 426, "Episode_Total": 21, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "For insider news, photos, and more visit <a href=\"http://www.thesimpsons.com/\" target=\"_blank\">The Simpsons official website</a>", "KeyArt_URL": "https://ib4.hulu.com/show_key_art/58?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/58?size=476x268&region=US"}');
