INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (685142, 'For as long as he can remember, Ichigo Kurosaki has been able to see ghosts. But when he meets Rukia, a Soul Reaper who battles evil spirits known as Hollows, he finds his life is changed forever when Rukia transfers most of her powers to him. Now a Soul Reaper himself with a new found wealth of spiritual energy, Ichigo discovers his true calling: to protect the living and the dead from evil. But when Rukia''s actions are called under scrutiny, Ichigo and his friends must put everything on the line to prepare to save their friend from the harsh justice of the Soul Society.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 732, "Episode_Total": 732, "Feature_Films": 0, "Seasons_Total": 26}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/1318?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (145623, 'Monkey D. Luffy refuses to let anyone or anything stand in the way of his quest to become king of all pirates. With a course charted for the treacherous waters of the Grand Line, this is one captain who’ll never drop anchor until he’s claimed the greatest treasure on Earth – the Legendary One Piece!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 4, "Videos_Total": null, "Episode_Total": 739, "Feature_Films": 0, "Seasons_Total": 11}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2138?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2138?size=476x268&region=US"}');
