INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (379847, 'From Academy Award nominee Lee Daniels (“Lee Daniels’ The Butler,” “Precious”) and Emmy Award winner Danny Strong (“Game Change,” “Lee Daniels’ The Butler”), comes EMPIRE, a sexy and powerful new drama about the head of a music empire whose three sons and wife all battle for his throne. Set to an original soundtrack written and produced by hip-hop hitmaker Timbaland, the family drama stars Academy Award nominee Terrence Howard (“Crash,” “Hustle & Flow”) and Academy Award and Emmy Award nominee Taraji P. Henson (“Person of Interest,” “The Curious Case of Benjamin Button”).', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 200, "Videos_Total": 248, "Episode_Total": 48, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/21027?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
