INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (186121, 'ABC''s Desperate Housewives offers a deliciously juicy glimpse into the lives of everyone''s favorite housewives. On the surface, the ladies of Wisteria Lane appear to be the picture of suburban America. But underneath lay bigger mysteries - infidelity, deceit, blackmail, and even murder. And with not-so-honest husbands, complicated relationships, family drama and meddling neighbors adding to the turmoil, it''s no wonder things aren''t always as they seem.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 323, "Videos_Total": 503, "Episode_Total": 166, "Feature_Films": 0, "Seasons_Total": 8}}', '{"Link_Desc": "Read bios, recaps and tour Wisteria Lane at the official <a href=\"http://abc.go.com/primetime/desperatehousewives/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">Desperate Housewives site</a>", "KeyArt_URL": "https://ib.hulu.com/show_key_art/2259?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/2259?size=476x268&region=US"}');
