INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (903625, '"CSI: Crime Scene Investigation" is a fast-paced drama about a team of forensic investigators trained to solve crimes by examining the evidence. They are on the case 24/7, scouring the scene, collecting the irrefutable evidence and finding the missing pieces that will solve the mystery.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 327, "Episode_Total": 337, "Feature_Films": 0, "Seasons_Total": 16}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/7889?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/7889?size=476x268&region=US"}');
