INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (381580, 'Steven Universe is about the misadventures of a boy named Steven, the ultimate "little brother" to a team of magical guardians of humanity—the Crystal Gems. Steven may not be as powerful as the Crystal Gems. Or as savvy. But that doesn''t stop him from joining Garnet, Amethyst and Pearl on their magical adventures and somehow finding a way to save the day!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 102, "Videos_Total": 192, "Episode_Total": 102, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/21721?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/21721?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (126189, 'The year is 2020, and after a deadly virus has swept the planet, only one man is left on earth: Phil Miller (Will Forte). He used to be just an average guy who loved his family and hated his job. Now, in his RV, Phil searches the country for other survivors. He has traveled to every city, every town and every outpost in the United States, Mexico and Canada, and has found no one. As he returns to his hometown of Tucson, Phil comes to the painful realization that he is almost certainly the last living being on the face of the earth. All he wants is for someone – anyone – to find him in Tucson – preferably a woman.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 65, "Videos_Total": 103, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/21985?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/21985?size=476x268&region=US"}');
