INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (255225, 'ABC’s distinctive late-night talk show features a diverse lineup of guests, including celebrities, athletes, comedians, politicians and human interest subjects. Along with a light-hearted and recognizable cast of characters, a hip house band and comedy bits in host Jimmy Kimmel’s inimitable style, the show additionally offers one of the funniest, freshest monologues on television today, drawing from all forms of topical media.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1605, "Videos_Total": 1621, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Music, photos, showcases, jokes and much more: It''s all on the official <a href=\"http://abc.go.com/latenight/jimmykimmel/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">JKL</a> site.", "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/2526?size=476x268&region=US"}');
