INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (909669, 'The Village Hidden in the Leaves is home to the stealthiest ninja in the land.  But twelve years earlier, a fearsome Nine-tailed Fox terrorized the village before it was subdued and its spirit sealed within the body of a baby boy.  Now that boy, Naruto, has grown up to become a hyperactive ninja-in-training who''s more interested in pranks than schoolwork...but Naruto is determined to become the greatest ninja ever!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 16, "Videos_Total": 613, "Episode_Total": 597, "Feature_Films": 0, "Seasons_Total": 9}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/1603?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/1603?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (158088, 'Emmy award-winning "Seinfeld" is one of the most popular shows on the air. Mining his rich comedic resources, Jerry Seinfeld provides a hysterical look at life as a single adult in the ''90s. Along with a refreshing cast and top-notch writing, this series is quickly becoming a comedy classic.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 63, "Videos_Total": 234, "Episode_Total": 171, "Feature_Films": 0, "Seasons_Total": 9}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/23104?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/23104?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (162806, 'Today''s American families come in all shapes and sizes. The cookie cutter mold of man + wife + 2.5 kids is a thing of the past, as it becomes quickly apparent in the bird''s eye view of ABC''s half-hour comedy, which takes an honest and often hilarious look at the composition and complexity of modern family life.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 68, "Videos_Total": 90, "Episode_Total": 22, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Cast bios, photos and chat: Interact on the official <a href=\"http://beta.abc.go.com/shows/modernfamily?CID=09_Hulu_ABC\" target=\"_blank\">Modern Family</a> website.", "KeyArt_URL": "https://ib2.hulu.com/show_key_art/2553?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/2553?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (703226, 'From the writer and director of Crazy, Stupid, Love comes a smart, modern new dramedy that will challenge your everyday presumptions about the people you think you know.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 71, "Videos_Total": 89, "Episode_Total": 18, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/28409?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/28409?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (194923, 'It''s one crazy adventure after another for human boy, Finn, and his best friend, Jake, a 28-year old dog with magical powers. They''re out to have the most fun possible and they sure do find it exploring the Land of Ooo! Whether it''s saving Princess Bubblegum, battling zombie candy, taunting the Ice King or rocking out with Marceline the Vampire Queen, with Finn and Jake it''s always ADVENTURE TIME!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 223, "Videos_Total": 435, "Episode_Total": 214, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/22416?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (529969, 'The doctors of Grey Sloan Memorial Hospital deal with life-or-death consequences on a daily basis – it''s in one another that they find comfort, friendship and, at times, more than friendship. Together they''re discovering that neither medicine nor relationships can be defined in black and white. Real life only comes in shades of grey.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 155, "Videos_Total": 164, "Episode_Total": 24, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "For photos and insider scoop from cast and crew visit the official <a href=\"http://abc.go.com/primetime/greysanatomy/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">Grey''s Anatomy site</a>", "KeyArt_URL": "https://ib3.hulu.com/show_key_art/2252?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/2252?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (746555, 'A legendary queen of country music struggles to maintain her place in the spotlight while dealing with an ambitious rising pop-country vixen who wants to knock her off the throne. From executive producer Callie Khouri (writer of Thelma & Louise) comes this contemporary musical drama about love, power, money, family and music. ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 426, "Videos_Total": 518, "Episode_Total": 107, "Feature_Films": 0, "Seasons_Total": 5}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/11226?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/11226?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (280553, 'This long-running animated comedy focuses on the eponymous family in the town of Springfield in an unnamed U.S. state. The head of the Simpson family, Homer, is not a typical family man. A nuclear-plant employee, he does his best to lead his family but often finds that they are leading him. The family includes loving, blue-haired matriarch Marge, troublemaking son Bart, overachieving daughter Lisa and baby Maggie. Other Springfield residents include the family''s religious neighbor, Ned Flanders, family physician Dr. Hibbert, Moe the bartender and police chief Clancy Wiggum.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 405, "Videos_Total": 426, "Episode_Total": 21, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "For insider news, photos, and more visit <a href=\"http://www.thesimpsons.com/\" target=\"_blank\">The Simpsons official website</a>", "KeyArt_URL": "https://ib4.hulu.com/show_key_art/58?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/58?size=476x268&region=US"}');
