INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (346849, 'Gumball’s world is pretty run-of-the-mill. He’s chased around school by a T-Rex. He has a friend named Anton who’s a piece of toast. He’s got a crush on Penny, a peanut with antlers. His dad is a 6’4” bunny. His mom works at a Rainbow Factory. And his brother is a goldfish named Darwin. Yup, everything looks perfectly normal here.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 156, "Videos_Total": 312, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/22015?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/22015?size=476x268&region=US"}');
