INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (253242, 'Mordecai – a sarcastic blue jay, and Rigby – a somewhat responsible raccoon, are best friends. They even work together at a park owned by Pops, a big lollipop-headed guy. Which seems normal enough. They’ve got a cranky gumball machine for a boss and they work alongside a Zen-like yeti named Skips. Yep. Everything is as regular as can be.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 220, "Videos_Total": 437, "Episode_Total": 217, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/22278?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/22278?size=476x268&region=US"}');
