INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (487153, 'Four famous musician coaches will each select singers to mentor into artists during the blind auditions. Once they have their teams, the star coaches will bring in their personal songwriters, producers, and high-powered friends to help their teams evolve. Ultimately, America will decide which singer will be worthy of the grand prize.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1024, "Videos_Total": 1024, "Episode_Total": 0, "Feature_Films": 0, "Seasons_Total": 0}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/6290?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
