INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (871872, 'An unscripted culinary boot camp that features the drama of aspiring restaurateurs competing for world-renowned Chef Gordon Ramsay’s approval and the chance to become America’s next culinary star.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 1, "Episode_Total": 0, "Feature_Films": 0, "Seasons_Total": 0}}', '{"Link_Desc": "For insider news, photos, and more visit the official <a href=\"http://www.fox.com/hellskitchen/\" target=\"_blank\">Hell''s Kitchen website</a>", "KeyArt_URL": "https://ib2.hulu.com/show_key_art/148?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/148?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (285600, 'From Academy Award nominee Lee Daniels (“Lee Daniels’ The Butler,” “Precious”) and Emmy Award winner Danny Strong (“Game Change,” “Lee Daniels’ The Butler”), comes EMPIRE, a sexy and powerful new drama about the head of a music empire whose three sons and wife all battle for his throne. Set to an original soundtrack written and produced by hip-hop hitmaker Timbaland, the family drama stars Academy Award nominee Terrence Howard (“Crash,” “Hustle & Flow”) and Academy Award and Emmy Award nominee Taraji P. Henson (“Person of Interest,” “The Curious Case of Benjamin Button”).', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 200, "Videos_Total": 240, "Episode_Total": 48, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/21027?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/21027?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (857705, 'An unscripted series in which Gordon Ramsay attempts to turn deserted restaurants into the most sought-after venues in town.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 93, "Episode_Total": 92, "Feature_Films": 0, "Seasons_Total": 6}}', '{"Link_Desc": "For insider news, photos, and more visit the official <a href=\"http://www.fox.com/kitchennightmares/\" target=\"_blank\">Kitchen Nightmares</a> website", "KeyArt_URL": "https://ib3.hulu.com/show_key_art/57?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/57?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (905958, 'Wednesdays at 10pm on FXX. It''s Always Sunny in Philadelphia features Mac, Dennis, Charlie, Sweet Dee and Frank, five ne’er-do-wells who own and operate Paddy’s Pub in Philadelphia. Their constant scheming usually lands them in a world of hurt, yet they never seem to learn from their mistakes. As they say, some things never change. So prepare for more depraved schemes, half-baked arguments and absurdly underhanded plots to subvert one another.
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (434732, 'Keeping Up with the Kardashians takes viewers inside the hectic lives of Hollywood''s modern-day Brady Bunch. Can two famous clans come together as one united front? Or will their individual lust for the limelight end up fracturing the family?', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 683, "Videos_Total": 864, "Episode_Total": 181, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/150?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/150?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (392507, 'Julianna Margulies (ER) ignites the screen as Alicia Florrick, the political wife whose world is shattered when her husband (Chris Noth, Sex & the City, Law & Order) is caught in a sex and corruption scandal. Forced to support her family, Alicia returns to work at a Chicago law firm headed by Diane Lockhart (Emmy and Tony Award winner Christine Baranski) and Will Gardner (Josh Charles), a driven attorney with a passion for justice. A gripping blend of courtroom drama, politics and steamy personal relationships, THE GOOD WIFE features an A-List cast of regulars and guest stars like Michael J. Fox, Matthew Perry and Rita Wilson. Hailed by the Chicago Tribune for its “deluxe production values, smart writing, and outstanding array of actors,” the series earned 14 Emmy nominations in its first two seasons alone. With fascinating characters and timely scripts torn from the headlines, the verdict is in: THE GOOD WIFE is great entertainment.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 157, "Episode_Total": 156, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/15094?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/15094?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (114207, 'For nearly 65 years, generations of young children have been charmed by the literary adventures of Curious George. Now George is ready for his next big adventure! Based on the best-selling Curious George books by Margret and H.A. Rey, the series expands George’s world to include a host of colorful new characters and original locales, while maintaining the charm of the beloved books. The series aims to inspire kids to explore science, math, and engineering in the world around them.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 108, "Episode_Total": 108, "Feature_Films": 0, "Seasons_Total": 9}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/13844?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/13844?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (155980, 'The Village Hidden in the Leaves is home to the stealthiest ninja in the land.  But twelve years earlier, a fearsome Nine-tailed Fox terrorized the village before it was subdued and its spirit sealed within the body of a baby boy--Naruto Uzumaki!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 440, "Episode_Total": 440, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/1304?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/1304?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (330739, 'Andre ''Dre'' Johnson has a great job, a beautiful wife, Rainbow, four kids, and a colonial home in the ''burbs. But has success brought too much assimilation for this black family?', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 229, "Videos_Total": 301, "Episode_Total": 61, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/19738?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/19738?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (338527, 'From the writer and director of Crazy, Stupid, Love comes a smart, modern new dramedy that will challenge your everyday presumptions about the people you think you know.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 71, "Videos_Total": 89, "Episode_Total": 18, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/28409?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/28409?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (505562, 'The year is 2020, and after a deadly virus has swept the planet, only one man is left on earth: Phil Miller (Will Forte). He used to be just an average guy who loved his family and hated his job. Now, in his RV, Phil searches the country for other survivors. He has traveled to every city, every town and every outpost in the United States, Mexico and Canada, and has found no one. As he returns to his hometown of Tucson, Phil comes to the painful realization that he is almost certainly the last living being on the face of the earth. All he wants is for someone – anyone – to find him in Tucson – preferably a woman.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 65, "Videos_Total": 113, "Episode_Total": 48, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/21985?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (432363, 'ABC''s Desperate Housewives offers a deliciously juicy glimpse into the lives of everyone''s favorite housewives. On the surface, the ladies of Wisteria Lane appear to be the picture of suburban America. But underneath lay bigger mysteries - infidelity, deceit, blackmail, and even murder. And with not-so-honest husbands, complicated relationships, family drama and meddling neighbors adding to the turmoil, it''s no wonder things aren''t always as they seem.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 323, "Videos_Total": 489, "Episode_Total": 175, "Feature_Films": 0, "Seasons_Total": 8}}', '{"Link_Desc": "Read bios, recaps and tour Wisteria Lane at the official <a href=\"http://abc.go.com/primetime/desperatehousewives/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">Desperate Housewives site</a>", "KeyArt_URL": "https://ib.hulu.com/show_key_art/2259?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/2259?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (769751, '"CSI: Crime Scene Investigation" is a fast-paced drama about a team of forensic investigators trained to solve crimes by examining the evidence. They are on the case 24/7, scouring the scene, collecting the irrefutable evidence and finding the missing pieces that will solve the mystery.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 337, "Episode_Total": 329, "Feature_Films": 0, "Seasons_Total": 16}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/7889?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/7889?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (416701, 'Archer chronicles an international spy agency and the lives of its employees. Although their work of espionage, reconnaissance missions, wiretapping and undercover surveillance is daunting and dangerous, every covert operation and global crisis is actually just another excuse for the staff to undermine, sabotage and betray each other for personal gain. ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 14, "Videos_Total": 99, "Episode_Total": 85, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/3433?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/3433?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (502299, 'Young women of various backgrounds, shapes and sizes compete to prove that they can make it in the high-stress, high-stakes world of modeling. With mentoring by supermodel Tyra Banks and exposure to prolific fashion-industry gurus, the finalists compete in an accelerated modeling boot camp. Participants learn to master complicated catwalks, fashion photo shoots and perfect publicity skills, all under 24-hour-a-day surveillance of the cameras that chronicle every move.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 271, "Episode_Total": 283, "Feature_Films": 0, "Seasons_Total": 22}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/8322?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/8322?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (581619, 'Join Jimmy Fallon for a daily mix of jokes, sketches, celebrity interviews and musical guests.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 3442, "Videos_Total": 3460, "Episode_Total": 18, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/17312?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/17312?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (562349, 'Tired of watching just one comedian at a time? Get a pair. Catch sketch comedy masters and best friends Keegan-Michael Key and Jordan Peele for a half hour of irreverent wit, pop-culture impressions and escalating absurdity.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 96, "Videos_Total": 134, "Episode_Total": 53, "Feature_Films": 0, "Seasons_Total": 5}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/8898?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/8898?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (925274, 'The Golden Girls is the story of four older women who share a house in Miami Beach, Florida. Bea Arthur plays Dorothy, a divorced school teacher, with a sardonic wit. Rue McClanahan plays Blanche, a man-hunting Southern Belle. Betty White plays Rose, a very sweet woman who is somewhat spacey. Rounding out the trio is Estelle Getty, playing Dorothy''s outspoken mother, Sophia. ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 181, "Episode_Total": 180, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/29524?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (219429, 'Steven Universe is about the misadventures of a boy named Steven, the ultimate "little brother" to a team of magical guardians of humanity—the Crystal Gems. Steven may not be as powerful as the Crystal Gems. Or as savvy. But that doesn''t stop him from joining Garnet, Amethyst and Pearl on their magical adventures and somehow finding a way to save the day!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 102, "Videos_Total": null, "Episode_Total": 102, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/21721?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/21721?size=476x268&region=US"}');
