INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (690876, 'Murder, mob wars, and mansions? It’s just all in a day’s work for the residents of Port Charles, New York. With such notable characters as Sonny Corinthos (Maurice Benard) and Jason Morgan (Billy Miller), there’s never a dull moment – especially when you add to the mix their long-time revolving love affairs with Carly (Laura Wright), Samantha (Kelly Monaco), Elizabeth (Rebecca Herbst), Olivia (Lisa LoCicero), and Claudia (Sarah Brown). Couples like Robin and Patrick (Kimberly McCullough and Jason Thompson) and Maxie and Spinelli (Kirsten Storms and Bradford Anderson), and families like the quarreling (but lovable) Quartermaines, even out this dysfunctional town.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1052, "Videos_Total": null, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Get character 101s and more at the official <a href=\"http://abc.go.com/shows/general-hospital/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">General Hospital</a> site.", "KeyArt_URL": "https://ib2.hulu.com/show_key_art/2440?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
