INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (553343, 'A vast international plot explodes when a beautiful Jane Doe is discovered naked in Times Square, completely covered in mysterious, intricate tattoos with no memory of who she is or how she got there. But there''s one tattoo that is impossible to miss: the name of FBI agent Kurt Weller, emblazoned across her back. "Jane," Agent Weller and the rest of the FBI quickly realize that each mark on her body is a crime to solve, leading them closer to the truth about her identity and the mysteries to be revealed. From Executive Producer Greg Berlanti ("The Mysteries of Laura," "The Flash," "Arrow").', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 49, "Videos_Total": 88, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/24499?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/24499?size=476x268&region=US"}');
