INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (320819, 'In The O.C., the lives of a group of friends and families are forever changed when an outsider arrives to their affluent community of Newport Beach in Orange County, California. From Josh Schwartz, the executive producer of Gossip Girl and Chuck, the series became a pop-culture phenomenon with its mix of heart, humor, drama and romance.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 3, "Videos_Total": 95, "Episode_Total": 78, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/1201?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/1201?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (680484, 'Frankie Heck is a superhero. Well, no, not an actual superhero - not unless you count getting her kids out the door for school every morning as a superfeat. Middle-aged, middle class and living in the middle of the country, this harried wife and working mother of three uses her wry wit and sense of humor to try to get her family through each day intact. Frankie has a job selling cars at the town''s only surviving car dealer; her husband, Mike, is a manager at the local quarry. Together, they''re putting THE MIDDLE on the map.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 43, "Videos_Total": 48, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Hang out with Patricia Heaton and interact with <a href=\"http://abc.go.com/shows/themiddle/index?CID=09_Hulu_ABC\" target=\"_blank\">The Middle</a> on the official site.", "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2624?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2624?size=476x268&region=US"}');
