INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (534346, 'From executive producers David Greenwalt (Angel, Buffy the Vampire Slayer) and Jim Kouf (Angel, National Treasure) comes a new world of police work where all cases have a storybook connection, but not always happily ever after.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 44, "Videos_Total": 49, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/7281?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/7281?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (293451, 'From renowned, Emmy Award-winning executive producer Dick Wolf ("Law & Order" brand) and creators Derek Haas and Michael Brandt, the writing team behind "3:10 to Yuma," comes the high-octane drama "Chicago Fire," -- an edge-of-your-seat view into the lives of everyday heroes committed to one of America’s noblest professions.  For the firefighters, rescue squad and paramedics of Chicago Firehouse 51, no occupation is more stressful or dangerous, yet so rewarding and exhilarating.  These courageous men and women are among the elite who forge headfirst into danger when everyone else is running the other way and whose actions make the difference between life and death.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 65, "Videos_Total": 70, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/11258?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/11258?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (599015, 'The ''Grey''s Anatomy'' spin-off focuses on neonatal surgeon Addison Forbes Montgomery, who has left Seattle Grace and moved to L.A., where she practices at the upscale Oceanside Wellness Clinic with her divorced medical-school friends Naomi and Sam Bennett.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 246, "Videos_Total": 352, "Episode_Total": 111, "Feature_Films": 0, "Seasons_Total": 6}}', '{"Link_Desc": "Get music, photos, recaps and much more on the <a href=\"http://abc.go.com/primetime/privatepractice/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">official Private Practice site</a>", "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2313?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2313?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (776970, 'The Village Hidden in the Leaves is home to the stealthiest ninja in the land.  But twelve years earlier, a fearsome Nine-tailed Fox terrorized the village before it was subdued and its spirit sealed within the body of a baby boy.  Now that boy, Naruto, has grown up to become a hyperactive ninja-in-training who''s more interested in pranks than schoolwork...but Naruto is determined to become the greatest ninja ever!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 16, "Videos_Total": 613, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 9}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/1603?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/1603?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (394781, 'Kagome is a modern high school girl who doesn''t believe in the old myths and legends surrounding her grandfather''s shrine. That is, until the day she falls into the shrine''s well and into another time! In Japan''s ancient past, Kagome joins the half demon Inuyasha on a quest to find the scattered shards of the Shikon Jewel, a gem so powerful that demons from across the land will do anything to get even a piece. Along the way they gain friends, battle enemies, and prepare to face their deadliest foe and rival for the Shikon Jewel--Naraku!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 324, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/2324?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (684606, 'The Devil has come to Los Angeles…Based upon the characters created by Neil Gaiman, Sam Kieth and Mike Dringenberg for DC Entertainment’s Vertigo imprint, LUCIFER is the story of the original fallen angel. Bored and unhappy as the Lord of Hell, LUCIFER MORNINGSTAR (Tom Ellis has abandoned his throne and retired to L.A., where he owns Lux, an upscale nightclub.  Charming, charismatic and devilishly handsome, Lucifer is enjoying his retirement, indulging in a few of his favorite things – wine, women and song – when a beautiful pop star is brutally murdered outside of Lux. For the first time in roughly 10 billion years, he feels something awaken deep within him as a result of this murder. Compassion? Sympathy? The very thought disturbs him – as well as his best friend and confidante, MAZIKEEN aka MAZE (Lesley-Ann Brandt), a fierce demon in the form of a beautiful young woman.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 33, "Videos_Total": 64, "Episode_Total": 31, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/26058?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/26058?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (915317, 'Straight-talking comic girl-next-door Amy Schumer is exposing herself -- and her messy world of dating, drinking and public debacles -- when she steps out from behind the microphone for an all-new, genre-busting comedy series.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 79, "Videos_Total": 118, "Episode_Total": 39, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/14027?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/14027?size=476x268&region=US"}');
