INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (568872, 'Twin brother and sister Dipper and Mabel Pines are in for an unexpected adventure when they spend the summer with their great uncle in the mysterious town of Gravity Falls, Oregon. Upon their arrival, Dipper and Mabel''s huckster great uncle, also known as Grunkle Stan, enlists the siblings'' help in running The Mystery Shack, a fun tourist trap he owns that overcharges unsuspecting customers. Although Dipper and Mabel quickly discover The Mystery Shack itself is a hoax, they sense there is something strange about their new town and together they begin to unlock the secrets of Gravity Falls.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 41, "Episode_Total": 40, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/28109?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/28109?size=476x268&region=US"}');
