INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (918854, 'Today''s American families come in all shapes and sizes. The cookie cutter mold of man + wife + 2.5 kids is a thing of the past, as it becomes quickly apparent in the bird''s eye view of ABC''s half-hour comedy, which takes an honest and often hilarious look at the composition and complexity of modern family life.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 68, "Videos_Total": null, "Episode_Total": 22, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Cast bios, photos and chat: Interact on the official <a href=\"http://beta.abc.go.com/shows/modernfamily?CID=09_Hulu_ABC\" target=\"_blank\">Modern Family</a> website.", "KeyArt_URL": "https://ib2.hulu.com/show_key_art/2553?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/2553?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (845414, 'It''s one crazy adventure after another for human boy, Finn, and his best friend, Jake, a 28-year old dog with magical powers. They''re out to have the most fun possible and they sure do find it exploring the Land of Ooo! Whether it''s saving Princess Bubblegum, battling zombie candy, taunting the Ice King or rocking out with Marceline the Vampire Queen, with Finn and Jake it''s always ADVENTURE TIME!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 223, "Videos_Total": 437, "Episode_Total": 223, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/22416?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/22416?size=476x268&region=US"}');
