INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (852713, 'From Academy Award nominee Lee Daniels (“Lee Daniels’ The Butler,” “Precious”) and Emmy Award winner Danny Strong (“Game Change,” “Lee Daniels’ The Butler”), comes EMPIRE, a sexy and powerful new drama about the head of a music empire whose three sons and wife all battle for his throne. Set to an original soundtrack written and produced by hip-hop hitmaker Timbaland, the family drama stars Academy Award nominee Terrence Howard (“Crash,” “Hustle & Flow”) and Academy Award and Emmy Award nominee Taraji P. Henson (“Person of Interest,” “The Curious Case of Benjamin Button”).', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 200, "Videos_Total": 243, "Episode_Total": 48, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/21027?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/21027?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (502447, 'Wednesdays at 10pm on FXX. It''s Always Sunny in Philadelphia features Mac, Dennis, Charlie, Sweet Dee and Frank, five ne’er-do-wells who own and operate Paddy’s Pub in Philadelphia. Their constant scheming usually lands them in a world of hurt, yet they never seem to learn from their mistakes. As they say, some things never change. So prepare for more depraved schemes, half-baked arguments and absurdly underhanded plots to subvert one another.
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (761649, 'Archer chronicles an international spy agency and the lives of its employees. Although their work of espionage, reconnaissance missions, wiretapping and undercover surveillance is daunting and dangerous, every covert operation and global crisis is actually just another excuse for the staff to undermine, sabotage and betray each other for personal gain. ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 14, "Videos_Total": 99, "Episode_Total": 85, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/3433?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/3433?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (620026, 'Julianna Margulies (ER) ignites the screen as Alicia Florrick, the political wife whose world is shattered when her husband (Chris Noth, Sex & the City, Law & Order) is caught in a sex and corruption scandal. Forced to support her family, Alicia returns to work at a Chicago law firm headed by Diane Lockhart (Emmy and Tony Award winner Christine Baranski) and Will Gardner (Josh Charles), a driven attorney with a passion for justice. A gripping blend of courtroom drama, politics and steamy personal relationships, THE GOOD WIFE features an A-List cast of regulars and guest stars like Michael J. Fox, Matthew Perry and Rita Wilson. Hailed by the Chicago Tribune for its “deluxe production values, smart writing, and outstanding array of actors,” the series earned 14 Emmy nominations in its first two seasons alone. With fascinating characters and timely scripts torn from the headlines, the verdict is in: THE GOOD WIFE is great entertainment.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 157, "Episode_Total": 156, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/15094?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/15094?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (363971, 'For nearly 65 years, generations of young children have been charmed by the literary adventures of Curious George. Now George is ready for his next big adventure! Based on the best-selling Curious George books by Margret and H.A. Rey, the series expands George’s world to include a host of colorful new characters and original locales, while maintaining the charm of the beloved books. The series aims to inspire kids to explore science, math, and engineering in the world around them.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": null, "Episode_Total": 108, "Feature_Films": 0, "Seasons_Total": 9}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/13844?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/13844?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (380297, 'The Village Hidden in the Leaves is home to the stealthiest ninja in the land.  But twelve years earlier, a fearsome Nine-tailed Fox terrorized the village before it was subdued and its spirit sealed within the body of a baby boy--Naruto Uzumaki!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": null, "Episode_Total": 428, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/1304?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/1304?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (736840, 'Andre ''Dre'' Johnson has a great job, a beautiful wife, Rainbow, four kids, and a colonial home in the ''burbs. But has success brought too much assimilation for this black family?', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 229, "Videos_Total": 301, "Episode_Total": 67, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/19738?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/19738?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (954560, 'The year is 2020, and after a deadly virus has swept the planet, only one man is left on earth: Phil Miller (Will Forte). He used to be just an average guy who loved his family and hated his job. Now, in his RV, Phil searches the country for other survivors. He has traveled to every city, every town and every outpost in the United States, Mexico and Canada, and has found no one. As he returns to his hometown of Tucson, Phil comes to the painful realization that he is almost certainly the last living being on the face of the earth. All he wants is for someone – anyone – to find him in Tucson – preferably a woman.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 65, "Videos_Total": 113, "Episode_Total": 48, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/21985?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (243263, 'ABC''s Desperate Housewives offers a deliciously juicy glimpse into the lives of everyone''s favorite housewives. On the surface, the ladies of Wisteria Lane appear to be the picture of suburban America. But underneath lay bigger mysteries - infidelity, deceit, blackmail, and even murder. And with not-so-honest husbands, complicated relationships, family drama and meddling neighbors adding to the turmoil, it''s no wonder things aren''t always as they seem.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 323, "Videos_Total": 503, "Episode_Total": 180, "Feature_Films": 0, "Seasons_Total": 8}}', '{"Link_Desc": "Read bios, recaps and tour Wisteria Lane at the official <a href=\"http://abc.go.com/primetime/desperatehousewives/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">Desperate Housewives site</a>", "KeyArt_URL": "https://ib.hulu.com/show_key_art/2259?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/2259?size=476x268&region=US"}');
