INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (358695, 'A former media relations consultant to the President, Olivia Pope (Kerry Washington) dedicates her life to protecting and defending the public images of our nation''s elite. After leaving the White House, the power consultant opened her own firm, hoping to start a new chapter -- both professionally and personally -- but she can''t seem to completely cut ties with her past. Slowly it becomes apparent that her staff, who specialize in fixing the lives of other people, can''t quite fix the ones closest at hand -- their own.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 167, "Videos_Total": 172, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/9673?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/9673?size=476x268&region=US"}');
