INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (669768, 'ABC’s distinctive late-night talk show features a diverse lineup of guests, including celebrities, athletes, comedians, politicians and human interest subjects. Along with a light-hearted and recognizable cast of characters, a hip house band and comedy bits in host Jimmy Kimmel’s inimitable style, the show additionally offers one of the funniest, freshest monologues on television today, drawing from all forms of topical media.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1605, "Videos_Total": 1613, "Episode_Total": 16, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Music, photos, showcases, jokes and much more: It''s all on the official <a href=\"http://abc.go.com/latenight/jimmykimmel/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">JKL</a> site.", "KeyArt_URL": "https://ib2.hulu.com/show_key_art/2526?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/2526?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (360155, 'Everyone''s favorite soft-spoken neighbor Cleveland Brown moves to his hometown in Virginia with his 14-year old son, Cleveland JR. Many years ago, Cleveland was a high school student madly in love with a beautiful girl named Donna. Much to his dismay, his love went unrequited, and Donna wound up marrying another man. Cleveland once told Donna he would always love her, and if this man ever done her wrong, he''d be there when she called. Well, this man done her wrong.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 88, "Episode_Total": 83, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": "For insider news, photos, and more visit the official <a href=\"http://www.fox.com/cleveland/\" target=\"_blank\">The Cleveland Show</a> website", "KeyArt_URL": "https://ib.hulu.com/show_key_art/2295?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/2295?size=476x268&region=US"}');
