INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (406928, 'In this modern-day twist on Washington Irving''s classic, ICHABOD CRANE is resurrected and pulled two and a half centuries through time to find that the world is on the brink of destruction, forcing him to team up with a contemporary police officer to unravel a mystery that dates back to the founding fathers.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 48, "Videos_Total": 110, "Episode_Total": 49, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/15138?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/15138?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (364685, 'From renowned, Emmy Award-winning executive producer Dick Wolf ("Law & Order" brand) and creators Derek Haas and Michael Brandt, the writing team behind "3:10 to Yuma," comes the high-octane drama "Chicago Fire," -- an edge-of-your-seat view into the lives of everyday heroes committed to one of America’s noblest professions.  For the firefighters, rescue squad and paramedics of Chicago Firehouse 51, no occupation is more stressful or dangerous, yet so rewarding and exhilarating.  These courageous men and women are among the elite who forge headfirst into danger when everyone else is running the other way and whose actions make the difference between life and death.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 65, "Videos_Total": 56, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/11258?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/11258?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (970798, 'The ''Grey''s Anatomy'' spin-off focuses on neonatal surgeon Addison Forbes Montgomery, who has left Seattle Grace and moved to L.A., where she practices at the upscale Oceanside Wellness Clinic with her divorced medical-school friends Naomi and Sam Bennett.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 246, "Videos_Total": 343, "Episode_Total": 111, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": "Get music, photos, recaps and much more on the <a href=\"http://abc.go.com/primetime/privatepractice/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">official Private Practice site</a>", "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2313?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2313?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (808655, 'Revealing an entirely new chapter that has never been told, in the rise of the great DC Comics Super-Villains and vigilantes, GOTHAM follows one cop, destined for greatness, as he navigates a dangerously corrupt city teetering between good and evil, and chronicles the birth of one of the most popular super heroes of our time.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 120, "Videos_Total": 120, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/19289?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (967700, 'The Devil has come to Los Angeles…Based upon the characters created by Neil Gaiman, Sam Kieth and Mike Dringenberg for DC Entertainment’s Vertigo imprint, LUCIFER is the story of the original fallen angel. Bored and unhappy as the Lord of Hell, LUCIFER MORNINGSTAR (Tom Ellis has abandoned his throne and retired to L.A., where he owns Lux, an upscale nightclub.  Charming, charismatic and devilishly handsome, Lucifer is enjoying his retirement, indulging in a few of his favorite things – wine, women and song – when a beautiful pop star is brutally murdered outside of Lux. For the first time in roughly 10 billion years, he feels something awaken deep within him as a result of this murder. Compassion? Sympathy? The very thought disturbs him – as well as his best friend and confidante, MAZIKEEN aka MAZE (Lesley-Ann Brandt), a fierce demon in the form of a beautiful young woman.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 33, "Videos_Total": 64, "Episode_Total": 31, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/26058?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
