INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (335893, 'For as long as he can remember, Ichigo Kurosaki has been able to see ghosts. But when he meets Rukia, a Soul Reaper who battles evil spirits known as Hollows, he finds his life is changed forever when Rukia transfers most of her powers to him. Now a Soul Reaper himself with a new found wealth of spiritual energy, Ichigo discovers his true calling: to protect the living and the dead from evil. But when Rukia''s actions are called under scrutiny, Ichigo and his friends must put everything on the line to prepare to save their friend from the harsh justice of the Soul Society.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": null, "Episode_Total": 718, "Feature_Films": 0, "Seasons_Total": 26}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/1318?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/1318?size=476x268&region=US"}');
