INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (920658, 'A bottle of wine tastes just as good when you pay with all pennies. That''s a fact. And no matter what the city throws at twenty-somethings Abbi and Ilana, these broads are all in. Catch the totally fresh, new series based on the acclaimed digital shorts.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 60, "Videos_Total": 90, "Episode_Total": 30, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/16937?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/16937?size=476x268&region=US"}');
