INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (877872, 'Step through the stargate with SG-1, a team of soldiers and scientists, as they travel instantaneously to other planets to explore, forge alliances, defuse crises, establish trade, investigate ancient mysteries, and defend Earth from such hostile forces as the Goa''uld, the Replicators, and the Ori.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 214, "Episode_Total": 214, "Feature_Films": 0, "Seasons_Total": 10}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/1861?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/1861?size=476x268&region=US"}');
