INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (449875, 'Frankie Heck is a superhero. Well, no, not an actual superhero - not unless you count getting her kids out the door for school every morning as a superfeat. Middle-aged, middle class and living in the middle of the country, this harried wife and working mother of three uses her wry wit and sense of humor to try to get her family through each day intact. Frankie has a job selling cars at the town''s only surviving car dealer; her husband, Mike, is a manager at the local quarry. Together, they''re putting THE MIDDLE on the map.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 43, "Videos_Total": 48, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Hang out with Patricia Heaton and interact with <a href=\"http://abc.go.com/shows/themiddle/index?CID=09_Hulu_ABC\" target=\"_blank\">The Middle</a> on the official site.", "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2624?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2624?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (109522, 'From renowned, Emmy Award-winning executive producer Dick Wolf ("Law & Order" brand) and creators Derek Haas and Michael Brandt, the writing team behind "3:10 to Yuma," comes the high-octane drama "Chicago Fire," -- an edge-of-your-seat view into the lives of everyday heroes committed to one of America’s noblest professions.  For the firefighters, rescue squad and paramedics of Chicago Firehouse 51, no occupation is more stressful or dangerous, yet so rewarding and exhilarating.  These courageous men and women are among the elite who forge headfirst into danger when everyone else is running the other way and whose actions make the difference between life and death.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 65, "Videos_Total": 70, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/11258?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (764799, 'The ''Grey''s Anatomy'' spin-off focuses on neonatal surgeon Addison Forbes Montgomery, who has left Seattle Grace and moved to L.A., where she practices at the upscale Oceanside Wellness Clinic with her divorced medical-school friends Naomi and Sam Bennett.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 246, "Videos_Total": 357, "Episode_Total": 111, "Feature_Films": 0, "Seasons_Total": 6}}', '{"Link_Desc": "Get music, photos, recaps and much more on the <a href=\"http://abc.go.com/primetime/privatepractice/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">official Private Practice site</a>", "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2313?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2313?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (607462, 'The Devil has come to Los Angeles…Based upon the characters created by Neil Gaiman, Sam Kieth and Mike Dringenberg for DC Entertainment’s Vertigo imprint, LUCIFER is the story of the original fallen angel. Bored and unhappy as the Lord of Hell, LUCIFER MORNINGSTAR (Tom Ellis has abandoned his throne and retired to L.A., where he owns Lux, an upscale nightclub.  Charming, charismatic and devilishly handsome, Lucifer is enjoying his retirement, indulging in a few of his favorite things – wine, women and song – when a beautiful pop star is brutally murdered outside of Lux. For the first time in roughly 10 billion years, he feels something awaken deep within him as a result of this murder. Compassion? Sympathy? The very thought disturbs him – as well as his best friend and confidante, MAZIKEEN aka MAZE (Lesley-Ann Brandt), a fierce demon in the form of a beautiful young woman.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 33, "Videos_Total": 64, "Episode_Total": 31, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/26058?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/26058?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (350691, 'Straight-talking comic girl-next-door Amy Schumer is exposing herself -- and her messy world of dating, drinking and public debacles -- when she steps out from behind the microphone for an all-new, genre-busting comedy series.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 79, "Videos_Total": 118, "Episode_Total": 39, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/14027?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/14027?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (139609, 'Based on the best-selling crime novels, Angie Harmon and Sasha Alexander star as detective Jane Rizzoli and medical examiner Maura Isles. Opposites in many ways -- Rizzoli is brash and tomboyish; the methodical and impeccably dressed Isles is often icy -- together, they use their brilliant minds to bust Boston''s most notorious criminals.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": null, "Episode_Total": 96, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/19145?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/19145?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (701583, 'See life from the ground up with Tommy, Chuckie, Susie, Lil, Phil, and the hardly angelic, Angelica. Usually led by fearless leader Tommy, the Rugrats turn the ordinary into the extraordinary and every day into the perfect setting for adventure!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 166, "Episode_Total": 166, "Feature_Films": 0, "Seasons_Total": 9}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/25243?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/25243?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (191357, 'Twin brother and sister Dipper and Mabel Pines are in for an unexpected adventure when they spend the summer with their great uncle in the mysterious town of Gravity Falls, Oregon. Upon their arrival, Dipper and Mabel''s huckster great uncle, also known as Grunkle Stan, enlists the siblings'' help in running The Mystery Shack, a fun tourist trap he owns that overcharges unsuspecting customers. Although Dipper and Mabel quickly discover The Mystery Shack itself is a hoax, they sense there is something strange about their new town and together they begin to unlock the secrets of Gravity Falls.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 41, "Episode_Total": 40, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/28109?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (809014, 'A provocative yet sophisticated drama about four women and their love lives, their sex lives, their secrets, their lies, and above all, their friendship. From ABC Studios, and based on the hit BBC series of the same name, this is Executive Produced by Bob Sertner ("Revenge," "No Ordinary Family"), KJ Steinberg ("Gilded Lilys," "Gossip Girl") and Rina Mimoun ("Privileged," "Gilmore Girls"). ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 53, "Episode_Total": 52, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/11266?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (620203, 'Revealing an entirely new chapter that has never been told, in the rise of the great DC Comics Super-Villains and vigilantes, GOTHAM follows one cop, destined for greatness, as he navigates a dangerously corrupt city teetering between good and evil, and chronicles the birth of one of the most popular super heroes of our time.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 120, "Videos_Total": 125, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/19289?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/19289?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (504020, 'Kagome is a modern high school girl who doesn''t believe in the old myths and legends surrounding her grandfather''s shrine. That is, until the day she falls into the shrine''s well and into another time! In Japan''s ancient past, Kagome joins the half demon Inuyasha on a quest to find the scattered shards of the Shikon Jewel, a gem so powerful that demons from across the land will do anything to get even a piece. Along the way they gain friends, battle enemies, and prepare to face their deadliest foe and rival for the Shikon Jewel--Naraku!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 335, "Episode_Total": 334, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/2324?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/2324?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (582678, 'Clarence finds something amazing in just about everything. Discover the best that life has to offer--epic pinecone wars, backyard tree forts and the secret worlds beyond milk cartons--all through the eyes of Clarence and his friends, the unpredictable Sumo and overly-cautious Jeff.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 77, "Videos_Total": 154, "Episode_Total": 77, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/23481?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/23481?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (712319, 'While Drake is laid back and goes with the flow, Josh lives strictly by the rules! But when Josh''s dad and Drake''s mom get married, these two totally opposite boys become stepbrothers!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 47, "Episode_Total": 47, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/20977?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/20977?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (397660, 'Football-headed Arnold lives with his offbeat grandparents and pet pig in a boarding house inhabited by a bunch of eccentrics. With his best buddy Gerald, Arnold endures playground bullies, crushes, and everything else that comes with big-city life.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 99, "Episode_Total": 99, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/20969?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/20969?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (861321, 'Today''s American families come in all shapes and sizes. The cookie cutter mold of man + wife + 2.5 kids is a thing of the past, as it becomes quickly apparent in the bird''s eye view of ABC''s half-hour comedy, which takes an honest and often hilarious look at the composition and complexity of modern family life.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 68, "Videos_Total": 81, "Episode_Total": 22, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Cast bios, photos and chat: Interact on the official <a href=\"http://beta.abc.go.com/shows/modernfamily?CID=09_Hulu_ABC\" target=\"_blank\">Modern Family</a> website.", "KeyArt_URL": "https://ib2.hulu.com/show_key_art/2553?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/2553?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (946412, 'It''s one crazy adventure after another for human boy, Finn, and his best friend, Jake, a 28-year old dog with magical powers. They''re out to have the most fun possible and they sure do find it exploring the Land of Ooo! Whether it''s saving Princess Bubblegum, battling zombie candy, taunting the Ice King or rocking out with Marceline the Vampire Queen, with Finn and Jake it''s always ADVENTURE TIME!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 223, "Videos_Total": 433, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/22416?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/22416?size=476x268&region=US"}');
