INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (706278, 'The doctors of Grey Sloan Memorial Hospital deal with life-or-death consequences on a daily basis – it''s in one another that they find comfort, friendship and, at times, more than friendship. Together they''re discovering that neither medicine nor relationships can be defined in black and white. Real life only comes in shades of grey.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 155, "Videos_Total": 171, "Episode_Total": 24, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "For photos and insider scoop from cast and crew visit the official <a href=\"http://abc.go.com/primetime/greysanatomy/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">Grey''s Anatomy site</a>", "KeyArt_URL": "https://ib3.hulu.com/show_key_art/2252?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/2252?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (727680, 'Mordecai – a sarcastic blue jay, and Rigby – a somewhat responsible raccoon, are best friends. They even work together at a park owned by Pops, a big lollipop-headed guy. Which seems normal enough. They’ve got a cranky gumball machine for a boss and they work alongside a Zen-like yeti named Skips. Yep. Everything is as regular as can be.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 220, "Videos_Total": 437, "Episode_Total": 217, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/22278?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/22278?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (492967, 'This long-running animated comedy focuses on the eponymous family in the town of Springfield in an unnamed U.S. state. The head of the Simpson family, Homer, is not a typical family man. A nuclear-plant employee, he does his best to lead his family but often finds that they are leading him. The family includes loving, blue-haired matriarch Marge, troublemaking son Bart, overachieving daughter Lisa and baby Maggie. Other Springfield residents include the family''s religious neighbor, Ned Flanders, family physician Dr. Hibbert, Moe the bartender and police chief Clancy Wiggum.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 405, "Videos_Total": 412, "Episode_Total": 21, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "For insider news, photos, and more visit <a href=\"http://www.thesimpsons.com/\" target=\"_blank\">The Simpsons official website</a>", "KeyArt_URL": "https://ib4.hulu.com/show_key_art/58?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/58?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (368017, 'BROOKLYN NINE-NINE is an ensemble comedy about a talented-but-carefree detective, a by-the-book police captain and their precinct colleagues. While based in the workplace, the series is not really about the job – it’s about the men and women behind the badge.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 155, "Videos_Total": 245, "Episode_Total": 90, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/15137?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/15137?size=476x268&region=US"}');
