INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (999780, 'A legendary queen of country music struggles to maintain her place in the spotlight while dealing with an ambitious rising pop-country vixen who wants to knock her off the throne. From executive producer Callie Khouri (writer of Thelma & Louise) comes this contemporary musical drama about love, power, money, family and music. ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 426, "Videos_Total": 528, "Episode_Total": 95, "Feature_Films": 0, "Seasons_Total": 5}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/11226?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/11226?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (258973, 'Rick and Morty is a show about a sociopathic scientist who drags his unintelligent grandson on insanely dangerous adventures across the universe. Created and executive produced by Dan Harmon (Community, Channel 101) and Justin Roiland (House of Cosbys).', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 21, "Videos_Total": 42, "Episode_Total": 21, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/22881?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/22881?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (877894, 'College is over but the party isn’t. Join three best buds as they share a job, a crash pad and a promise to never let work get in the way of a good time—on this raucously original series.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 69, "Videos_Total": 155, "Episode_Total": 86, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/6341?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/6341?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (844745, 'For as long as he can remember, Ichigo Kurosaki has been able to see ghosts. But when he meets Rukia, a Soul Reaper who battles evil spirits known as Hollows, he finds his life is changed forever when Rukia transfers most of her powers to him. Now a Soul Reaper himself with a new found wealth of spiritual energy, Ichigo discovers his true calling: to protect the living and the dead from evil. But when Rukia''s actions are called under scrutiny, Ichigo and his friends must put everything on the line to prepare to save their friend from the harsh justice of the Soul Society.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 732, "Episode_Total": 732, "Feature_Films": 0, "Seasons_Total": 26}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/1318?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/1318?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (805688, 'Monkey D. Luffy refuses to let anyone or anything stand in the way of his quest to become king of all pirates. With a course charted for the treacherous waters of the Grand Line, this is one captain who’ll never drop anchor until he’s claimed the greatest treasure on Earth – the Legendary One Piece!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 4, "Videos_Total": 751, "Episode_Total": 747, "Feature_Films": 0, "Seasons_Total": 11}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2138?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2138?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (851990, 'Four famous musician coaches will each select singers to mentor into artists during the blind auditions. Once they have their teams, the star coaches will bring in their personal songwriters, producers, and high-powered friends to help their teams evolve. Ultimately, America will decide which singer will be worthy of the grand prize.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1024, "Videos_Total": 1024, "Episode_Total": 0, "Feature_Films": 0, "Seasons_Total": 0}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/6290?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/6290?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (851933, 'A magical animated series about a six-year-old girl, Doc McStuffins, who has the ability to talk to and heal toys and stuffed animals! With the help of her stuffed animal friends, Doc runs a clinic for toys out of her playhouse. The series emphasizes the importance of lending a helping hand, or paw, when people and toys need it most.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 81, "Episode_Total": 92, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/22638?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/22638?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (158387, 'An unscripted culinary boot camp that features the drama of aspiring restaurateurs competing for world-renowned Chef Gordon Ramsay’s approval and the chance to become America’s next culinary star.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 1, "Episode_Total": 0, "Feature_Films": 0, "Seasons_Total": 0}}', '{"Link_Desc": "For insider news, photos, and more visit the official <a href=\"http://www.fox.com/hellskitchen/\" target=\"_blank\">Hell''s Kitchen website</a>", "KeyArt_URL": "https://ib2.hulu.com/show_key_art/148?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/148?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (705495, 'From Academy Award nominee Lee Daniels (“Lee Daniels’ The Butler,” “Precious”) and Emmy Award winner Danny Strong (“Game Change,” “Lee Daniels’ The Butler”), comes EMPIRE, a sexy and powerful new drama about the head of a music empire whose three sons and wife all battle for his throne. Set to an original soundtrack written and produced by hip-hop hitmaker Timbaland, the family drama stars Academy Award nominee Terrence Howard (“Crash,” “Hustle & Flow”) and Academy Award and Emmy Award nominee Taraji P. Henson (“Person of Interest,” “The Curious Case of Benjamin Button”).', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 200, "Videos_Total": 239, "Episode_Total": 48, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/21027?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/21027?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (121881, 'Wednesdays at 10pm on FXX. It''s Always Sunny in Philadelphia features Mac, Dennis, Charlie, Sweet Dee and Frank, five ne’er-do-wells who own and operate Paddy’s Pub in Philadelphia. Their constant scheming usually lands them in a world of hurt, yet they never seem to learn from their mistakes. As they say, some things never change. So prepare for more depraved schemes, half-baked arguments and absurdly underhanded plots to subvert one another.
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (751414, 'Keeping Up with the Kardashians takes viewers inside the hectic lives of Hollywood''s modern-day Brady Bunch. Can two famous clans come together as one united front? Or will their individual lust for the limelight end up fracturing the family?', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 683, "Videos_Total": 864, "Episode_Total": 173, "Feature_Films": 0, "Seasons_Total": 12}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/150?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/150?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (357238, 'A bottle of wine tastes just as good when you pay with all pennies. That''s a fact. And no matter what the city throws at twenty-somethings Abbi and Ilana, these broads are all in. Catch the totally fresh, new series based on the acclaimed digital shorts.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 60, "Videos_Total": 90, "Episode_Total": 30, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/16937?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (594960, 'Julianna Margulies (ER) ignites the screen as Alicia Florrick, the political wife whose world is shattered when her husband (Chris Noth, Sex & the City, Law & Order) is caught in a sex and corruption scandal. Forced to support her family, Alicia returns to work at a Chicago law firm headed by Diane Lockhart (Emmy and Tony Award winner Christine Baranski) and Will Gardner (Josh Charles), a driven attorney with a passion for justice. A gripping blend of courtroom drama, politics and steamy personal relationships, THE GOOD WIFE features an A-List cast of regulars and guest stars like Michael J. Fox, Matthew Perry and Rita Wilson. Hailed by the Chicago Tribune for its “deluxe production values, smart writing, and outstanding array of actors,” the series earned 14 Emmy nominations in its first two seasons alone. With fascinating characters and timely scripts torn from the headlines, the verdict is in: THE GOOD WIFE is great entertainment.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 150, "Episode_Total": 148, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/15094?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/15094?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (543381, 'For nearly 65 years, generations of young children have been charmed by the literary adventures of Curious George. Now George is ready for his next big adventure! Based on the best-selling Curious George books by Margret and H.A. Rey, the series expands George’s world to include a host of colorful new characters and original locales, while maintaining the charm of the beloved books. The series aims to inspire kids to explore science, math, and engineering in the world around them.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 93, "Episode_Total": 108, "Feature_Films": 0, "Seasons_Total": 9}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/13844?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/13844?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (335576, 'The Village Hidden in the Leaves is home to the stealthiest ninja in the land.  But twelve years earlier, a fearsome Nine-tailed Fox terrorized the village before it was subdued and its spirit sealed within the body of a baby boy--Naruto Uzumaki!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 440, "Episode_Total": 440, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/1304?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/1304?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (912913, 'The Goldbergs are a loving family like any other, just with a lot more yelling, but for geeky 11-year old Adam these were his wonder years and he faced them armed with a video camera to capture all the crazy.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 169, "Videos_Total": null, "Episode_Total": 95, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/15360?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/15360?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (552614, 'Master Splinter allows the Turtles to visit the surface for the first time, where they''ll learn the importance of working as a team, uncover the mystery of their existence, and face fearsome enemies such as the Kraang and the ruthless Shredder.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 44, "Videos_Total": 144, "Episode_Total": 100, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/12138?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/12138?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (764483, 'ABC''s Desperate Housewives offers a deliciously juicy glimpse into the lives of everyone''s favorite housewives. On the surface, the ladies of Wisteria Lane appear to be the picture of suburban America. But underneath lay bigger mysteries - infidelity, deceit, blackmail, and even murder. And with not-so-honest husbands, complicated relationships, family drama and meddling neighbors adding to the turmoil, it''s no wonder things aren''t always as they seem.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 323, "Videos_Total": null, "Episode_Total": 175, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": "Read bios, recaps and tour Wisteria Lane at the official <a href=\"http://abc.go.com/primetime/desperatehousewives/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">Desperate Housewives site</a>", "KeyArt_URL": "https://ib.hulu.com/show_key_art/2259?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/2259?size=476x268&region=US"}');
