INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (765387, '"CSI: Crime Scene Investigation" is a fast-paced drama about a team of forensic investigators trained to solve crimes by examining the evidence. They are on the case 24/7, scouring the scene, collecting the irrefutable evidence and finding the missing pieces that will solve the mystery.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 337, "Episode_Total": 337, "Feature_Films": 0, "Seasons_Total": 16}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/7889?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (502921, 'Archer chronicles an international spy agency and the lives of its employees. Although their work of espionage, reconnaissance missions, wiretapping and undercover surveillance is daunting and dangerous, every covert operation and global crisis is actually just another excuse for the staff to undermine, sabotage and betray each other for personal gain. ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 14, "Videos_Total": 86, "Episode_Total": 85, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/3433?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/3433?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (276459, 'Young women of various backgrounds, shapes and sizes compete to prove that they can make it in the high-stress, high-stakes world of modeling. With mentoring by supermodel Tyra Banks and exposure to prolific fashion-industry gurus, the finalists compete in an accelerated modeling boot camp. Participants learn to master complicated catwalks, fashion photo shoots and perfect publicity skills, all under 24-hour-a-day surveillance of the cameras that chronicle every move.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": null, "Episode_Total": 283, "Feature_Films": 0, "Seasons_Total": 22}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/8322?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/8322?size=476x268&region=US"}');
