INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (565188, 'Sabrina is a normal teenager, except for one thing -- she''s a witch! Guided by her aunts, who come from a long line of witches, and Salem, a mischievous warlock doing penance as a black cat, Sabrina continually struggles to harness her powers while wittingly wreaking havoc on friends and foes alike. While struggling through the growing pains associated with being a witch and getting into lots of harmless trouble along the way, Sabrina realizes that magic is not quite as easy as pointing your finger.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 156, "Episode_Total": 148, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/12844?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/12844?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (496513, 'From Executive Producer Mark Burnett comes an inventive new reality series you can sink your teeth into. Budding entrepreneurs with big ideas can still make their dreams come true and ABC is about to give them the chance to make it happen. Each week a group of self-made millionaires from all corners of the business world take their own hard earned money and offer everyday people their one true shot at making their dreams a reality. Some will sink, some will swim and some will be eaten alive.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 18, "Videos_Total": null, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": "Get to know <a href=\"http://abc.go.com/primetime/sharktank/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">Shark Tank</a> on the official site!", "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2458?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2458?size=476x268&region=US"}');
