INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (492180, 'Everyone''s favorite soft-spoken neighbor Cleveland Brown moves to his hometown in Virginia with his 14-year old son, Cleveland JR. Many years ago, Cleveland was a high school student madly in love with a beautiful girl named Donna. Much to his dismay, his love went unrequited, and Donna wound up marrying another man. Cleveland once told Donna he would always love her, and if this man ever done her wrong, he''d be there when she called. Well, this man done her wrong.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 77, "Episode_Total": 88, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": "For insider news, photos, and more visit the official <a href=\"http://www.fox.com/cleveland/\" target=\"_blank\">The Cleveland Show</a> website", "KeyArt_URL": "https://ib.hulu.com/show_key_art/2295?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/2295?size=476x268&region=US"}');
