INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (917234, 'Comedy series set in Seattle, WA, which chronicles the lives of an eloquently pompous radio show host Dr. Frasier Crane (Kelsey Grammer), his brazen radio producer Roz (Peri Gilpin), his competitive, high-brow brother Niles (David Hyde Pierce), their crotchety father Martin (John Mahoney) and his quirky live-in nurse Daphne (Jane Leeves). ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 264, "Episode_Total": 250, "Feature_Films": 0, "Seasons_Total": 11}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/12867?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/12867?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (137608, 'Twin brother and sister Dipper and Mabel Pines are in for an unexpected adventure when they spend the summer with their great uncle in the mysterious town of Gravity Falls, Oregon. Upon their arrival, Dipper and Mabel''s huckster great uncle, also known as Grunkle Stan, enlists the siblings'' help in running The Mystery Shack, a fun tourist trap he owns that overcharges unsuspecting customers. Although Dipper and Mabel quickly discover The Mystery Shack itself is a hoax, they sense there is something strange about their new town and together they begin to unlock the secrets of Gravity Falls.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 41, "Episode_Total": 40, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/28109?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/28109?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (145496, 'A provocative yet sophisticated drama about four women and their love lives, their sex lives, their secrets, their lies, and above all, their friendship. From ABC Studios, and based on the hit BBC series of the same name, this is Executive Produced by Bob Sertner ("Revenge," "No Ordinary Family"), KJ Steinberg ("Gilded Lilys," "Gossip Girl") and Rina Mimoun ("Privileged," "Gilmore Girls"). ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 44, "Episode_Total": 41, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/11266?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (759420, 'Clarence finds something amazing in just about everything. Discover the best that life has to offer--epic pinecone wars, backyard tree forts and the secret worlds beyond milk cartons--all through the eyes of Clarence and his friends, the unpredictable Sumo and overly-cautious Jeff.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 77, "Videos_Total": 154, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/23481?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/23481?size=476x268&region=US"}');
