INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (472849, 'Football-headed Arnold lives with his offbeat grandparents and pet pig in a boarding house inhabited by a bunch of eccentrics. With his best buddy Gerald, Arnold endures playground bullies, crushes, and everything else that comes with big-city life.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 99, "Episode_Total": 88, "Feature_Films": 0, "Seasons_Total": 5}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/20969?size=476x268&region=US"}');
