INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (1349, 'The beloved show "Sesame Street" combines education and entertainment to make a meaningful difference in children''s lives. Besides teaching letters and numbers, "Sesame Street" fosters imagination, builds social skills, and models respect for people''s differences, whether they''re based in race, gender, ethnicity, googly eyes, or neon fur.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 7, "Videos_Total": null, "Episode_Total": 60, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/1349?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/1349?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (159834, 'It''s one crazy adventure after another for human boy, Finn, and his best friend, Jake, a 28-year old dog with magical powers. They''re out to have the most fun possible and they sure do find it exploring the Land of Ooo! Whether it''s saving Princess Bubblegum, battling zombie candy, taunting the Ice King or rocking out with Marceline the Vampire Queen, with Finn and Jake it''s always ADVENTURE TIME!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 223, "Videos_Total": 446, "Episode_Total": 223, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/22416?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/22416?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (760992, 'Disbarred lawyer Jeff Winger enrolls in a local community college. While there, he forms a study group who eventually learn more about themselves than their course work.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 96, "Episode_Total": 96, "Feature_Films": 0, "Seasons_Total": 6}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/2505?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/2505?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (463429, 'The doctors of Grey Sloan Memorial Hospital deal with life-or-death consequences on a daily basis – it''s in one another that they find comfort, friendship and, at times, more than friendship. Together they''re discovering that neither medicine nor relationships can be defined in black and white. Real life only comes in shades of grey.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 155, "Videos_Total": 179, "Episode_Total": 24, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "For photos and insider scoop from cast and crew visit the official <a href=\"http://abc.go.com/primetime/greysanatomy/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">Grey''s Anatomy site</a>", "KeyArt_URL": "https://ib3.hulu.com/show_key_art/2252?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/2252?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (952499, 'A magical animated series about a six-year-old girl, Doc McStuffins, who has the ability to talk to and heal toys and stuffed animals! With the help of her stuffed animal friends, Doc runs a clinic for toys out of her playhouse. The series emphasizes the importance of lending a helping hand, or paw, when people and toys need it most.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 92, "Episode_Total": 92, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/22638?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (113615, 'This long-running animated comedy focuses on the eponymous family in the town of Springfield in an unnamed U.S. state. The head of the Simpson family, Homer, is not a typical family man. A nuclear-plant employee, he does his best to lead his family but often finds that they are leading him. The family includes loving, blue-haired matriarch Marge, troublemaking son Bart, overachieving daughter Lisa and baby Maggie. Other Springfield residents include the family''s religious neighbor, Ned Flanders, family physician Dr. Hibbert, Moe the bartender and police chief Clancy Wiggum.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 405, "Videos_Total": 426, "Episode_Total": 21, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "For insider news, photos, and more visit <a href=\"http://www.thesimpsons.com/\" target=\"_blank\">The Simpsons official website</a>", "KeyArt_URL": "https://ib4.hulu.com/show_key_art/58?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (759924, 'BROOKLYN NINE-NINE is an ensemble comedy about a talented-but-carefree detective, a by-the-book police captain and their precinct colleagues. While based in the workplace, the series is not really about the job – it’s about the men and women behind the badge.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 155, "Videos_Total": 245, "Episode_Total": 90, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/15137?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/15137?size=476x268&region=US"}');
