INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (406016, 'From Academy Award nominee Lee Daniels (“Lee Daniels’ The Butler,” “Precious”) and Emmy Award winner Danny Strong (“Game Change,” “Lee Daniels’ The Butler”), comes EMPIRE, a sexy and powerful new drama about the head of a music empire whose three sons and wife all battle for his throne. Set to an original soundtrack written and produced by hip-hop hitmaker Timbaland, the family drama stars Academy Award nominee Terrence Howard (“Crash,” “Hustle & Flow”) and Academy Award and Emmy Award nominee Taraji P. Henson (“Person of Interest,” “The Curious Case of Benjamin Button”).', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 200, "Videos_Total": 248, "Episode_Total": 48, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/21027?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/21027?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (417399, 'Steven Universe is about the misadventures of a boy named Steven, the ultimate "little brother" to a team of magical guardians of humanity—the Crystal Gems. Steven may not be as powerful as the Crystal Gems. Or as savvy. But that doesn''t stop him from joining Garnet, Amethyst and Pearl on their magical adventures and somehow finding a way to save the day!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 102, "Videos_Total": 204, "Episode_Total": 87, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/21721?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (881359, 'Wednesdays at 10pm on FXX. It''s Always Sunny in Philadelphia features Mac, Dennis, Charlie, Sweet Dee and Frank, five ne’er-do-wells who own and operate Paddy’s Pub in Philadelphia. Their constant scheming usually lands them in a world of hurt, yet they never seem to learn from their mistakes. As they say, some things never change. So prepare for more depraved schemes, half-baked arguments and absurdly underhanded plots to subvert one another.
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (228948, 'Keeping Up with the Kardashians takes viewers inside the hectic lives of Hollywood''s modern-day Brady Bunch. Can two famous clans come together as one united front? Or will their individual lust for the limelight end up fracturing the family?', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 683, "Videos_Total": 864, "Episode_Total": 181, "Feature_Films": 0, "Seasons_Total": null}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/150?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/150?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (389924, 'Julianna Margulies (ER) ignites the screen as Alicia Florrick, the political wife whose world is shattered when her husband (Chris Noth, Sex & the City, Law & Order) is caught in a sex and corruption scandal. Forced to support her family, Alicia returns to work at a Chicago law firm headed by Diane Lockhart (Emmy and Tony Award winner Christine Baranski) and Will Gardner (Josh Charles), a driven attorney with a passion for justice. A gripping blend of courtroom drama, politics and steamy personal relationships, THE GOOD WIFE features an A-List cast of regulars and guest stars like Michael J. Fox, Matthew Perry and Rita Wilson. Hailed by the Chicago Tribune for its “deluxe production values, smart writing, and outstanding array of actors,” the series earned 14 Emmy nominations in its first two seasons alone. With fascinating characters and timely scripts torn from the headlines, the verdict is in: THE GOOD WIFE is great entertainment.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": null, "Episode_Total": 156, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/15094?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (146802, 'For nearly 65 years, generations of young children have been charmed by the literary adventures of Curious George. Now George is ready for his next big adventure! Based on the best-selling Curious George books by Margret and H.A. Rey, the series expands George’s world to include a host of colorful new characters and original locales, while maintaining the charm of the beloved books. The series aims to inspire kids to explore science, math, and engineering in the world around them.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 108, "Episode_Total": 108, "Feature_Films": 0, "Seasons_Total": 9}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/13844?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/13844?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (593780, 'The Village Hidden in the Leaves is home to the stealthiest ninja in the land.  But twelve years earlier, a fearsome Nine-tailed Fox terrorized the village before it was subdued and its spirit sealed within the body of a baby boy--Naruto Uzumaki!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 440, "Episode_Total": 440, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/1304?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/1304?size=476x268&region=US"}');
