INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (625822, 'ABC''s Desperate Housewives offers a deliciously juicy glimpse into the lives of everyone''s favorite housewives. On the surface, the ladies of Wisteria Lane appear to be the picture of suburban America. But underneath lay bigger mysteries - infidelity, deceit, blackmail, and even murder. And with not-so-honest husbands, complicated relationships, family drama and meddling neighbors adding to the turmoil, it''s no wonder things aren''t always as they seem.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 323, "Videos_Total": 495, "Episode_Total": 180, "Feature_Films": 0, "Seasons_Total": 8}}', '{"Link_Desc": "Read bios, recaps and tour Wisteria Lane at the official <a href=\"http://abc.go.com/primetime/desperatehousewives/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">Desperate Housewives site</a>", "KeyArt_URL": "https://ib.hulu.com/show_key_art/2259?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/2259?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (345750, '"CSI: Crime Scene Investigation" is a fast-paced drama about a team of forensic investigators trained to solve crimes by examining the evidence. They are on the case 24/7, scouring the scene, collecting the irrefutable evidence and finding the missing pieces that will solve the mystery.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 337, "Episode_Total": 329, "Feature_Films": 0, "Seasons_Total": 16}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/7889?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/7889?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (259535, 'Archer chronicles an international spy agency and the lives of its employees. Although their work of espionage, reconnaissance missions, wiretapping and undercover surveillance is daunting and dangerous, every covert operation and global crisis is actually just another excuse for the staff to undermine, sabotage and betray each other for personal gain. ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 14, "Videos_Total": 99, "Episode_Total": 85, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": null}');
