INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (243158, 'Young women of various backgrounds, shapes and sizes compete to prove that they can make it in the high-stress, high-stakes world of modeling. With mentoring by supermodel Tyra Banks and exposure to prolific fashion-industry gurus, the finalists compete in an accelerated modeling boot camp. Participants learn to master complicated catwalks, fashion photo shoots and perfect publicity skills, all under 24-hour-a-day surveillance of the cameras that chronicle every move.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 283, "Episode_Total": 283, "Feature_Films": 0, "Seasons_Total": 22}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib2.hulu.com/show_key_art/8322?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/8322?size=476x268&region=US"}');
