INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (775726, 'A provocative yet sophisticated drama about four women and their love lives, their sex lives, their secrets, their lies, and above all, their friendship. From ABC Studios, and based on the hit BBC series of the same name, this is Executive Produced by Bob Sertner ("Revenge," "No Ordinary Family"), KJ Steinberg ("Gilded Lilys," "Gossip Girl") and Rina Mimoun ("Privileged," "Gilmore Girls"). ', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 39, "Episode_Total": 52, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/11266?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/11266?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (997713, 'Revealing an entirely new chapter that has never been told, in the rise of the great DC Comics Super-Villains and vigilantes, GOTHAM follows one cop, destined for greatness, as he navigates a dangerously corrupt city teetering between good and evil, and chronicles the birth of one of the most popular super heroes of our time.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 120, "Videos_Total": 125, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/19289?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/19289?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (660351, 'Kagome is a modern high school girl who doesn''t believe in the old myths and legends surrounding her grandfather''s shrine. That is, until the day she falls into the shrine''s well and into another time! In Japan''s ancient past, Kagome joins the half demon Inuyasha on a quest to find the scattered shards of the Shikon Jewel, a gem so powerful that demons from across the land will do anything to get even a piece. Along the way they gain friends, battle enemies, and prepare to face their deadliest foe and rival for the Shikon Jewel--Naraku!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 335, "Episode_Total": 334, "Feature_Films": 0, "Seasons_Total": 7}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/2324?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/2324?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (684710, 'Clarence finds something amazing in just about everything. Discover the best that life has to offer--epic pinecone wars, backyard tree forts and the secret worlds beyond milk cartons--all through the eyes of Clarence and his friends, the unpredictable Sumo and overly-cautious Jeff.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 77, "Videos_Total": 154, "Episode_Total": 77, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/23481?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/23481?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (573706, 'While Drake is laid back and goes with the flow, Josh lives strictly by the rules! But when Josh''s dad and Drake''s mom get married, these two totally opposite boys become stepbrothers!', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 47, "Episode_Total": 47, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib.hulu.com/show_key_art/20977?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/20977?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (903323, 'Football-headed Arnold lives with his offbeat grandparents and pet pig in a boarding house inhabited by a bunch of eccentrics. With his best buddy Gerald, Arnold endures playground bullies, crushes, and everything else that comes with big-city life.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 0, "Videos_Total": 99, "Episode_Total": 99, "Feature_Films": 0, "Seasons_Total": 5}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/20969?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/20969?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (626067, 'The beloved show "Sesame Street" combines education and entertainment to make a meaningful difference in children''s lives. Besides teaching letters and numbers, "Sesame Street" fosters imagination, builds social skills, and models respect for people''s differences, whether they''re based in race, gender, ethnicity, googly eyes, or neon fur.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 7, "Videos_Total": 67, "Episode_Total": 60, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib4.hulu.com/show_key_art/1349?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib4.hulu.com/show/1349?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (23170, 'From the Academy Award Nominated Director of “Up in the Air” and “Juno” comes Casual, a new comedy series about a bachelor brother and his newly divorced sister living under one roof again. Together, they coach each other through the crazy world of dating while raising her teenage daughter. Created by Zander Lehmann, Casual is executive produced by Jason Reitman, Zander Lehmann, Helen Estabrook, and Liz Tigelaar.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 20, "Videos_Total": null, "Episode_Total": 36, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/23170?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/23170?size=476x268&region=US"}');
