INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (651956, 'The beloved show "Sesame Street" combines education and entertainment to make a meaningful difference in children''s lives. Besides teaching letters and numbers, "Sesame Street" fosters imagination, builds social skills, and models respect for people''s differences, whether they''re based in race, gender, ethnicity, googly eyes, or neon fur.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 7, "Videos_Total": 67, "Episode_Total": null, "Feature_Films": 0, "Seasons_Total": 3}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": null}');
