INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (496437, 'Frankie Heck is a superhero. Well, no, not an actual superhero - not unless you count getting her kids out the door for school every morning as a superfeat. Middle-aged, middle class and living in the middle of the country, this harried wife and working mother of three uses her wry wit and sense of humor to try to get her family through each day intact. Frankie has a job selling cars at the town''s only surviving car dealer; her husband, Mike, is a manager at the local quarry. Together, they''re putting THE MIDDLE on the map.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 43, "Videos_Total": 48, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": "Hang out with Patricia Heaton and interact with <a href=\"http://abc.go.com/shows/themiddle/index?CID=09_Hulu_ABC\" target=\"_blank\">The Middle</a> on the official site.", "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2624?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2624?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (148220, 'In this modern-day twist on Washington Irving''s classic, ICHABOD CRANE is resurrected and pulled two and a half centuries through time to find that the world is on the brink of destruction, forcing him to team up with a contemporary police officer to unravel a mystery that dates back to the founding fathers.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 48, "Videos_Total": 110, "Episode_Total": 52, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/15138?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/15138?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (551804, 'From renowned, Emmy Award-winning executive producer Dick Wolf ("Law & Order" brand) and creators Derek Haas and Michael Brandt, the writing team behind "3:10 to Yuma," comes the high-octane drama "Chicago Fire," -- an edge-of-your-seat view into the lives of everyday heroes committed to one of America’s noblest professions.  For the firefighters, rescue squad and paramedics of Chicago Firehouse 51, no occupation is more stressful or dangerous, yet so rewarding and exhilarating.  These courageous men and women are among the elite who forge headfirst into danger when everyone else is running the other way and whose actions make the difference between life and death.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 65, "Videos_Total": null, "Episode_Total": 5, "Feature_Films": 0, "Seasons_Total": 1}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib2.hulu.com/show/11258?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (222940, 'The ''Grey''s Anatomy'' spin-off focuses on neonatal surgeon Addison Forbes Montgomery, who has left Seattle Grace and moved to L.A., where she practices at the upscale Oceanside Wellness Clinic with her divorced medical-school friends Naomi and Sam Bennett.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 246, "Videos_Total": 357, "Episode_Total": 111, "Feature_Films": 0, "Seasons_Total": 6}}', '{"Link_Desc": "Get music, photos, recaps and much more on the <a href=\"http://abc.go.com/primetime/privatepractice/index?pn=index&CID=09_Hulu_ABC\" target=\"_blank\">official Private Practice site</a>", "KeyArt_URL": "https://ib1.hulu.com/show_key_art/2313?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/2313?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (899736, 'Clarence finds something amazing in just about everything. Discover the best that life has to offer--epic pinecone wars, backyard tree forts and the secret worlds beyond milk cartons--all through the eyes of Clarence and his friends, the unpredictable Sumo and overly-cautious Jeff.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 77, "Videos_Total": 154, "Episode_Total": 77, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib3.hulu.com/show_key_art/23481?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib3.hulu.com/show/23481?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (658113, 'The Devil has come to Los Angeles…Based upon the characters created by Neil Gaiman, Sam Kieth and Mike Dringenberg for DC Entertainment’s Vertigo imprint, LUCIFER is the story of the original fallen angel. Bored and unhappy as the Lord of Hell, LUCIFER MORNINGSTAR (Tom Ellis has abandoned his throne and retired to L.A., where he owns Lux, an upscale nightclub.  Charming, charismatic and devilishly handsome, Lucifer is enjoying his retirement, indulging in a few of his favorite things – wine, women and song – when a beautiful pop star is brutally murdered outside of Lux. For the first time in roughly 10 billion years, he feels something awaken deep within him as a result of this murder. Compassion? Sympathy? The very thought disturbs him – as well as his best friend and confidante, MAZIKEEN aka MAZE (Lesley-Ann Brandt), a fierce demon in the form of a beautiful young woman.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 33, "Videos_Total": 64, "Episode_Total": 31, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/26058?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": "https://ib1.hulu.com/show/26058?size=476x268&region=US"}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (491608, 'In The O.C., the lives of a group of friends and families are forever changed when an outsider arrives to their affluent community of Newport Beach in Orange County, California. From Josh Schwartz, the executive producer of Gossip Girl and Chuck, the series became a pop-culture phenomenon with its mix of heart, humor, drama and romance.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 3, "Videos_Total": 95, "Episode_Total": 92, "Feature_Films": 0, "Seasons_Total": 4}}', '{"Link_Desc": null, "KeyArt_URL": "https://ib1.hulu.com/show_key_art/1201?size=1600x600&region=US", "Art_Copyright": null, "Thumbnail_URL": null}');
INSERT INTO public.content_info (content_key, story_outline, mediacounts, visualassets) VALUES (608042, 'Twin brother and sister Dipper and Mabel Pines are in for an unexpected adventure when they spend the summer with their great uncle in the mysterious town of Gravity Falls, Oregon. Upon their arrival, Dipper and Mabel''s huckster great uncle, also known as Grunkle Stan, enlists the siblings'' help in running The Mystery Shack, a fun tourist trap he owns that overcharges unsuspecting customers. Although Dipper and Mabel quickly discover The Mystery Shack itself is a hoax, they sense there is something strange about their new town and together they begin to unlock the secrets of Gravity Falls.', '{"content_volumes": {"Film_Clips": 0, "Clips_Total": 1, "Videos_Total": 41, "Episode_Total": 40, "Feature_Films": 0, "Seasons_Total": 2}}', '{"Link_Desc": null, "KeyArt_URL": null, "Art_Copyright": null, "Thumbnail_URL": "https://ib.hulu.com/show/28109?size=476x268&region=US"}');
